async (page) => {
  const accepted = page.locator('.answer.accepted-answer, .answer.js-answer.accepted-answer').first();
  const exists = await accepted.count();
  if (!exists) return {error:'no accepted'};
  const voteText = (await accepted.locator('.js-vote-count, .js-vote-count-up').first().innerText()).trim();
  const author = (await accepted.locator('.user-details a').first().innerText()).trim();
  const preCount = await accepted.locator('pre').count();
  const codeCount = await accepted.locator('code').count();
  const preOrCodeCount = await accepted.locator('pre, code').count();
  const standaloneCodeCount = await accepted.locator('code:not(pre code)').count();
  const header = await page.locator('#answers-header h2, h2[data-answercount], .answers-subheader h2').first().innerText();
  const totalAnswers = (header.match(/\d+/) || [''])[0];
  return {voteText, author, preCount, codeCount, preOrCodeCount, standaloneCodeCount, header, totalAnswers};
}

